-- Mapper Basement v1.0 replacement (2083 rows). GENERATED from
-- docs/ingredients/validation/mapper_basement.csv.
-- Self-contained + transactional: on a fresh DB (after 0006) OR a live DB with the
-- old v0.95 rows, this swaps the two stale CHECK constraints to the v1.0 vocabulary,
-- replaces all rows, and sets the dataset_version default. Idempotent (re-run = same).
begin;
alter table public.mapper_basement drop constraint if exists mapper_basement_verification_status_check;
alter table public.mapper_basement drop constraint if exists mapper_basement_storage_type_check;
delete from public.mapper_basement;
alter table public.mapper_basement add constraint mapper_basement_verification_status_check check (verification_status = any (array['Blocked','Estimated','Estimated / Needs Label Review','PI Calculated / Needs Label Review','Superseded Duplicate','Verified','Verified / Basis Check Needed','Verified / PI Calculated','Verified / Public Label']));
alter table public.mapper_basement add constraint mapper_basement_storage_type_check check (storage_type = any (array['ambient','ambient_dry','chilled','fresh','fresh_chilled','frozen','frozen_or_refrigerated','refrigerated']));
alter table public.mapper_basement alter column dataset_version set default 'v1.0';
do $$ begin if (select count(*) from public.mapper_basement) <> 2083 then raise exception 'mapper_basement row count %', (select count(*) from public.mapper_basement); end if; end $$;
commit;
